effect.shader:
//vec2 l2s( vec2 v ) {
//    return (vec4(v,0.,1.)*acLayerToScreen).xy;
//}

#define l2s(v) ((vec4(v,0.,1.)*acLayerToScreen).xy)

float star(vec2 st, vec2 center, float r, float insideRadiusScale, float points) {
    vec2 dc = st-center;
    float ir = r*insideRadiusScale;
    float a = (atan(dc.x,dc.y)+3.14159)/2.;
    float p = smoothstep(r,ir,length(dc));

    a = smoothstep(p,ir,abs(sin(a*points)));
    return clamp((p*1.264+a)*p*p,0.,1.);
}

void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec2 st = acLayerNorm;
    st.y = 1. - st.y;
    st -= 0.5;
    st.x *= acLayerSize.x/acLayerSize.y;

    float p = star(st,position/1000.0,radius,shine*0.995,pointCount);

    vec4 adjColor = clamp(vec4(mix(color.rgb+vec3(0.15,0.15,0.15),vec3(1.),0.05)*p*brightness,1.),0.,1.)*p;

    vec4 result;
    if( blendMode==1 ) {
        result = vec4((texColor.rgb/texColor.a)*adjColor.rgb,1.0) * texColor.a;
    } else if( blendMode==2 ) {
        result = vec4( 1.-((1.-(texColor.rgb/texColor.a))*(1.-adjColor.rgb)),1.0) * texColor.a;
    } else {
        result = adjColor*texColor.a;
        result = texColor*(1.-result.a) + result;
    }
    gl_FragColor = mix(texColor,result,alpha);
}
